Here's a complete test class demonstrating the key modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // Helper: create a DataFetcher with a fake handler
    private static DataFetcher CreateFetcher(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        var mock = new MockHandler(handler);
        return new DataFetcher(new HttpClient(mock));
    }

    // 1. Basic async test — just return Task, MSTest awaits it
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var fetcher = CreateFetcher((req, ct) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // 2. [Timeout] — MSTest cancels the test's CancellationToken after N ms.
    //    Access it via TestContext.CancellationTokenSource.Token.
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var fetcher = CreateFetcher(async (req, ct) =>
        {
            await Task.Delay(50, ct); // simulate short latency
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("fast")
            };
        });

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // 3. Verify that the method forwards the CancellationToken correctly
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var fetcher = CreateFetcher((req, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK));
        });

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // 4. Non-success status code throws HttpRequestException
    [TestMethod]
    public async Task FetchAsync_ThrowsOnNonSuccessStatus()
    {
        var fetcher = CreateFetcher((req, ct) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.NotFound)));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Minimal mock handler — no third-party mocking library needed
    private sealed class MockHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => handler(request, cancellationToken);
    }
}
```

**Key patterns shown:**

| Pattern | How |
|---|---|
| **Async tests** | Return `Task`, MSTest awaits automatically |
| **Timeouts** | `[Timeout(ms)]` — MSTest cancels the test if it exceeds the limit |
| **Cancellation** | Pass a pre-cancelled `CancellationTokenSource` and assert the exception |
| **Async assertions** | `Assert.ThrowsExactlyAsync<T>()` (MSTest v3.7+; use `ThrowsExceptionAsync<T>` on older versions) |
| **HttpClient mocking** | Custom `HttpMessageHandler` — no need for Moq/NSubstitute |
